files.packages/calculator/src/ops/add.js:
function addOne(value) {
  return value + 1;
}

function addMany(start, increments) {
  return increments.reduce((acc, inc) => acc + inc, start);
}

module.exports = { addOne, addMany };

files.packages/calculator/tests/add.test.js:
const test = require("node:test");
const assert = require("node:assert/strict");
const { addOne, addMany } = require("../src/ops/add");

test("addOne increments", () => {
  assert.equal(addOne(9), 10);
  assert.equal(addOne(-4), -3);
});

test("addMany sums list", () => {
  assert.equal(addMany(3, [1, 2, 3]), 9);
  assert.equal(addMany(0, [5, -2, -1]), 2);
});

files.packages/calculator/src/ops/add.js:
function addOne(value) {
  const out = value + 1;
  return out;
}

function addMany(start, increments) {
  let total = start;
  for (const item of increments) total += item;
  return total;
}

module.exports = { addOne, addMany };

